// --- 介面控制邏輯 ---

document.addEventListener('DOMContentLoaded', () => {
    // Tab Switching
    const tabs = document.querySelectorAll('.mode-selector .btn');
    const sections = document.querySelectorAll('.content-section');

    tabs.forEach(tab => {
        tab.addEventListener('click', () => {
            tabs.forEach(t => t.classList.remove('active'));
            sections.forEach(s => s.classList.remove('active'));
            
            tab.classList.add('active');
            const targetId = tab.getAttribute('data-mode');
            document.getElementById(targetId).classList.add('active');
        });
    });

    // 1. Read Aloud Logic
    const readerContent = document.getElementById('reader-content');
    readAloudData.forEach((item, index) => {
        const div = document.createElement('div');
        div.innerHTML = `<h3>${item.title}</h3><p id="read-p-${index}">${item.content.replace(/\n/g, '<br>')}</p>`;
        readerContent.appendChild(div);
    });

    const synth = window.speechSynthesis;
    let voices = [];
    const voiceSelect = document.getElementById('voice-select');

    function populateVoiceList() {
        voices = synth.getVoices().filter(voice => voice.lang.includes('zh'));
        voiceSelect.innerHTML = '';
        voices.forEach((voice, i) => {
            const option = document.createElement('option');
            option.textContent = `${voice.name} (${voice.lang})`;
            option.value = i;
            voiceSelect.appendChild(option);
        });
    }

    populateVoiceList();
    if (speechSynthesis.onvoiceschanged !== undefined) {
        speechSynthesis.onvoiceschanged = populateVoiceList;
    }

    let utterance = null;

    document.getElementById('play-btn').addEventListener('click', () => {
        if (synth.paused) {
            synth.resume();
            return;
        }
        synth.cancel();
        
        const fullText = readAloudData.map(d => d.title + "。" + d.content).join("。");
        utterance = new SpeechSynthesisUtterance(fullText);
        const selectedVoice = voices[voiceSelect.value];
        if(selectedVoice) utterance.voice = selectedVoice;
        utterance.rate = 1.0;
        synth.speak(utterance);
    });

    document.getElementById('pause-btn').addEventListener('click', () => {
        if (synth.speaking && !synth.paused) {
            synth.pause();
        }
    });

    document.getElementById('stop-btn').addEventListener('click', () => {
        synth.cancel();
    });

    // 2. Flashcard Logic
    let currentCardIndex = 0;
    const cardQTitle = document.getElementById('card-q-title');
    const cardQText = document.getElementById('card-q-text');
    const cardAText = document.getElementById('card-a-text');
    const counterText = document.getElementById('card-counter');
    const flashcard = document.querySelector('.flashcard');

    function loadCard(index) {
        flashcard.classList.remove('flipped');
        setTimeout(() => {
            cardQTitle.textContent = `問答題 Q${index + 1}`;
            cardQText.innerHTML = flashcardData[index].q;
            cardAText.innerHTML = flashcardData[index].a;
            counterText.textContent = `${index + 1} / ${flashcardData.length}`;
        }, 200); // Wait for unflip animation
    }

    flashcard.addEventListener('click', () => {
        flashcard.classList.toggle('flipped');
    });

    document.getElementById('prev-card').addEventListener('click', () => {
        if (currentCardIndex > 0) {
            currentCardIndex--;
            loadCard(currentCardIndex);
        }
    });

    document.getElementById('next-card').addEventListener('click', () => {
        if (currentCardIndex < flashcardData.length - 1) {
            currentCardIndex++;
            loadCard(currentCardIndex);
        }
    });

    loadCard(0);


    // 2. Quiz Logic
    let currentQuizIndex = 0;
    const quizTitle = document.getElementById('quiz-q-title');
    const quizOptions = document.getElementById('quiz-options');
    const quizExplanation = document.getElementById('quiz-explanation');
    const quizExplanationText = document.getElementById('quiz-explanation-text');
    const quizCounter = document.getElementById('quiz-counter');
    const prevQuizBtn = document.getElementById('prev-quiz');
    const nextQuizBtn = document.getElementById('next-quiz');

    function loadQuiz(index) {
        if (!quizData || quizData.length === 0 || !quizTitle) return;
        const qData = quizData[index];
        quizTitle.textContent = `Q${index + 1}: ${qData.q}`;
        quizCounter.textContent = `${index + 1} / ${quizData.length}`;
        quizExplanation.style.display = 'none';
        
        quizOptions.innerHTML = '';
        const answerLetter = qData.answer; // e.g., 'C'

        qData.options.forEach((optText) => {
            const btn = document.createElement('button');
            btn.className = 'quiz-option glass';
            btn.textContent = optText;
            
            btn.addEventListener('click', () => {
                // disable all options
                const allOpts = quizOptions.querySelectorAll('.quiz-option');
                allOpts.forEach(b => b.disabled = true);
                
                // check answer
                if (optText.startsWith(`(${answerLetter})`) || optText.startsWith(`${answerLetter})`)) {
                    btn.classList.add('correct');
                } else {
                    btn.classList.add('incorrect');
                    // highlight correct one
                    allOpts.forEach(b => {
                        if (b.textContent.startsWith(`(${answerLetter})`) || b.textContent.startsWith(`${answerLetter})`)) {
                            b.classList.add('correct');
                        }
                    });
                }
                
                quizExplanationText.innerHTML = qData.explanation;
                quizExplanation.style.display = 'block';
            });
            
            quizOptions.appendChild(btn);
        });
        
        prevQuizBtn.disabled = index === 0;
        nextQuizBtn.disabled = index === quizData.length - 1;
    }

    if (quizData && quizData.length > 0 && quizTitle) {
        loadQuiz(0);
    }

    if (prevQuizBtn && nextQuizBtn) {
        prevQuizBtn.addEventListener('click', () => {
            if (currentQuizIndex > 0) {
                currentQuizIndex--;
                loadQuiz(currentQuizIndex);
            }
        });

        nextQuizBtn.addEventListener('click', () => {
            if (currentQuizIndex < quizData.length - 1) {
                currentQuizIndex++;
                loadQuiz(currentQuizIndex);
            }
        });
    }

    // 3. Cloze Logic
    const clozeContent = document.getElementById('cloze-content');
    
    clozeData.forEach(item => {
        const div = document.createElement('div');
        div.className = 'glass cloze-card';
        div.innerHTML = `<h3>${item.title}</h3><p>${item.content}</p>`;
        clozeContent.appendChild(div);
    });

    // Add click events to cloze words
    const clozeWords = document.querySelectorAll('.cloze-word');
    clozeWords.forEach(word => {
        const answer = word.getAttribute('data-word');
        word.textContent = answer; 
        
        word.addEventListener('click', function() {
            this.classList.toggle('revealed');
        });
    });

    document.getElementById('reveal-all').addEventListener('click', () => {
        clozeWords.forEach(word => {
            word.classList.add('revealed');
        });
    });

    // 4. Sprint Logic
    const sprintContent = document.getElementById('sprint-content');
    if (sprintContent && typeof marked !== 'undefined') {
        sprintContent.innerHTML = marked.parse(sprintData);
    }

    const dictionaryContent = document.getElementById('dictionary-content');
    if (dictionaryContent && typeof marked !== 'undefined') {
        dictionaryContent.innerHTML = marked.parse(dictionaryData);
    }

});
